        for betu in szo:
            if betu.lower() in maganhangzok:
                uj_szo += betu + 'v' + betu
            else:
                uj_szo += betu
        kimenet.append(uj_szo)
    return ' '.join(kimenet)

szoveg = input('Írj be egy mondatot, amit teve nyelvre fordítok: ') # Kezdeti bemenet prompttal

while szoveg != "exit":
